#include <iostream>
#include <vector>
using namespace std;

template <class V>
class Node {
public:
    char key;
    vector<V> values;
    Node<V>* left;
    Node<V>* right;

    Node(char k, V v) {
        key = k;
        values.push_back(v);
        left = nullptr;
        right = nullptr;
    }
};

template <class V>
class ModifiedMap {
private:
    Node<V>* root;

    Node<V>* insert(Node<V>* node, char k, V v) {
        if (node == nullptr) return new Node<V>(k, v);

        if (k < node->key) node->left = insert(node->left, k, v);
        else if (k > node->key) node->right = insert(node->right, k, v);
        else node->values.push_back(v);

        return node;
    }

    Node<V>* findNode(Node<V>* node, char k) {
        if (node == nullptr || node->key == k) return node;
        if (k < node->key) return findNode(node->left, k);
        return findNode(node->right, k);
    }

public:
    ModifiedMap() { root = nullptr; }

    void insert(char k, V v) { root = insert(root, k, v); }

    void find(char k) {
        Node<V>* node = findNode(root, k);
        if (node == nullptr) {
            cout << "Key not found" << endl;
            return;
        }
        for (V value : node->values) cout << value << " ";
        cout << endl;
    }
};

#include <iostream>
#include <queue>
#include <map>
#include <string>
using namespace std;

struct Request {
    int id;
    string description;
    int importance;
    char status;
};

struct CompareRequest {
    bool operator()(const Request& a, const Request& b) {
        return a.importance < b.importance;
    }
};

priority_queue<Request, vector<Request>, CompareRequest> requestsQueue;
map<int, Request> requestsMap;

void request_service(int request_id, string request_description, int importance) {
    Request r = {request_id, request_description, importance, 'n'};
    requestsQueue.push(r);
    requestsMap[request_id] = r;
}

void print_requests() {
    for (auto item : requestsMap) {
        cout << item.first << " " << item.second.status << endl;
    }
}

int get_next_request() {
    while (!requestsQueue.empty()) {
        Request r = requestsQueue.top();
        requestsQueue.pop();
        if (requestsMap[r.id].status == 'n') return r.id;
    }
    return -1;
}

void set_request_status(int request_id, char status) {
    requestsMap[request_id].status = status;
}
